## 2. Hook Structure

### useToast Pattern
Located at `/Users/anotonio.silva/antonio/lol/src/hooks/use_toast.ts`

```typescript
export function useToast() {
  const [toasts, setToasts] = useState<ToastData[]>([]);
  const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  // Cleanup timers on unmount
  useEffect(() => {
    const timers = timersRef.current;
    return () => {
      timers.forEach(timer => clearTimeout(timer));
      timers.clear();
    };
  }, []);

  const hide = useCallback((id: string) => {
    // Mark as exiting for animation, then remove after EXIT_ANIMATION_MS (200ms)
    setToasts(prev =>
      prev.map(t => t.id === id ? { ...t, exiting: true } : t)
    );
    const exitTimer = setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, EXIT_ANIMATION_MS);
    timersRef.current.set(`${id}-exit`, exitTimer);
  }, []);

  const show = useCallback((options: ShowToastOptions) => {
    const id = String(nextId++);
    const toast: ToastData = { id, style: options.style ?? 'info', title: options.title, message: options.message, exiting: false };
    setToasts(prev => [toast, ...prev]);
    const timer = setTimeout(() => hide(id), AUTO_DISMISS_MS); // 3000ms
    timersRef.current.set(id, timer);
    return id;
  }, [hide]);

  return { toasts, show, hide };
}
```

**Key pattern**: Hooks expose state, callbacks, and return an object with intuitive API. Used in App.tsx as:
```typescript
const { toasts, show: showToast, hide: hideToast } = useToast();
```

